insert into public.exams (id, title, department_id, description, duration_minutes, question_count, passing_score, is_active, exam_type, year)
insert into public.questions (exam_id, question_text, question_type, options, correct_answer, explanation, marks, order_num) values
('b1c2d3e4-0001-4000-8000-000000000001','Which one of the following is False about static website?','mcq',ARRAY['Its content will be changed unless the actual webpage file is edited.','It is also referred as flat pages or stationary pages.','It will be delivered to the users as exactly stored in the files.','Its content remains the same for all viewers of the website.'],0,'Static websites content does NOT change unless the file is edited — so option A is false (it states content WILL be changed).',1,1),
('b1c2d3e4-0001-4000-8000-000000000001','Which one of the following is a server side scripting language?','mcq',ARRAY['PHP','ASP','Python','All of the above'],3,'PHP, ASP, and Python are all server-side scripting languages.',1,2),
('b1c2d3e4-0001-4000-8000-000000000001','A pop up box used to display information to user in JavaScript is called ___________.','mcq',ARRAY['Prompt','Alert','Confirm','All of the above'],1,'Alert() displays an informational popup to the user.',1,3),
('b1c2d3e4-0001-4000-8000-000000000001','What does this code possibly refer to: <link rel="stylesheet" href="styles.css">?','mcq',ARRAY['Defines a new CSS by the name styles','Calls an internal style sheet called styles','Calls an external style sheet called styles','Defines an inline CSS by the name styles'],2,'The link tag with rel="stylesheet" calls an external CSS file.',1,4),
('b1c2d3e4-0001-4000-8000-000000000001','What is the preferred way for adding a background color in HTML?','mcq',ARRAY['<body background="yellow">','<background>yellow</background>','<body style="background-color: yellow">','<background color="yellow">text<background>'],2,'The preferred way is inline CSS: style="background-color: yellow".',1,5),
('b1c2d3e4-0001-4000-8000-000000000001','What is the method used to get the result from the form data sent with both GET and POST?','mcq',ARRAY['$_REQUEST','$_POST','$_GET','A & B'],0,'$_REQUEST retrieves data from both GET and POST methods.',1,6),
('b1c2d3e4-0001-4000-8000-000000000001','Which of the following is an optional parameter while using mysqli_connect() method?','mcq',ARRAY['Localhost','Database','Username','Password'],1,'Database name is optional in mysqli_connect(); server, username, password are required.',1,7),
('b1c2d3e4-0001-4000-8000-000000000001','What Tag Is Used For Inserting A Line Break In A Html Page?','mcq',ARRAY['<break>','<ol>','<br>','<lb>'],2,'<br> is the HTML tag for a line break.',1,8),
('b1c2d3e4-0001-4000-8000-000000000001','Which Javascript Event Handler Pertains To Actions Enabled By Mouse Clicks?','mcq',ARRAY['Oninput','Onchange','Onclick','Ondrag'],2,'Onclick fires when an element is clicked.',1,9),
('b1c2d3e4-0001-4000-8000-000000000001','Which of the following are Advantages of modularization in software design?','mcq',ARRAY['Smaller components are difficult to maintain','Components with high cohesion can be re-used again','Program can be divided based on functional aspects','Desired from security aspect'],1,'High cohesion components are reusable — a key advantage of modularization.',1,10);
insert into public.questions (exam_id, question_text, question_type, options, correct_answer, explanation, marks, order_num) values
('b1c2d3e4-0001-4000-8000-000000000001','Which of the following is not element of Requirement Engineering Process?','mcq',ARRAY['Software Requirement Specification','Feasibility Study','Software Requirement Design','Requirement Gathering'],2,'Software Requirement Design is not a standard element of the Requirement Engineering Process.',1,11),
('b1c2d3e4-0001-4000-8000-000000000001','Which type of test determines if the system meets the entire requirements (functional and nonfunctional)?','mcq',ARRAY['Unit Test','Integration test','System test','Acceptance test'],3,'Acceptance test verifies the complete system against all requirements.',1,12),
('b1c2d3e4-0001-4000-8000-000000000001','How is generalization implemented in Object-Oriented software engineering?','mcq',ARRAY['Inheritance','Polymorphism','Encapsulation','Abstract Classes'],0,'Generalization is implemented through Inheritance in OOP.',1,13),
('b1c2d3e4-0001-4000-8000-000000000001','All of the following are required to develop an effective test except:','mcq',ARRAY['Detailed understanding of the system','Application and solution domain knowledge','Knowledge of the testing techniques','Skill to specific programming language'],3,'Testing does not require skill in a specific programming language.',1,14),
('b1c2d3e4-0001-4000-8000-000000000001','Use case description commonly contains:','mcq',ARRAY['Trigger, associations, guarantee.','Precondition, generalizations, main scenario.','Precondition, main scenario, alternative scenarios','None of the above'],2,'Use case descriptions include preconditions, main scenario, and alternative scenarios.',1,15),
('b1c2d3e4-0001-4000-8000-000000000001','It defines how and where data are organized in physical data storage','mcq',ARRAY['Internal Schema','Conceptual Schema','External Schema','External and Conceptual Schema'],0,'Internal Schema defines physical data organization and storage.',1,16),
('b1c2d3e4-0001-4000-8000-000000000001','During modeling your data, Entity Relationship is applied at','mcq',ARRAY['Applications and security','Physical refinement','Conceptual database','Schema refinement'],2,'ER modeling is applied at the conceptual database level.',1,17),
('b1c2d3e4-0001-4000-8000-000000000001','Criteria that should not be considered when evaluating or assessing requirement analysis?','mcq',ARRAY['Correctness','Need assessment','Consistency','Speed'],3,'Speed is not a criterion for evaluating requirement analysis.',1,18),
('b1c2d3e4-0001-4000-8000-000000000001','The SQL command to define the primary key for an existing table called Employee with primary column empid','mcq',ARRAY['ADD TABLE Employee ADD PRIMARY KEY (empid)','ATTACH TABLE Employee ADD PRIMARY KEY (empid)','ADD TABLE Employee ATTACH PRIMARY KEY (empid)','ALTER TABLE Employee ADD PRIMARY KEY (empid)'],3,'ALTER TABLE ... ADD PRIMARY KEY is correct SQL syntax.',1,19),
('b1c2d3e4-0001-4000-8000-000000000001','While checking normalization, the problem that does not exist on transitive dependency is','mcq',ARRAY['Modification Anomaly','Revoke Anomaly','Insertion Anomaly','Deletion Anomaly'],1,'Revoke Anomaly is not a database anomaly associated with transitive dependency.',1,20);
insert into public.questions (exam_id, question_text, question_type, options, correct_answer, explanation, marks, order_num) values
('b1c2d3e4-0001-4000-8000-000000000001','SELECT statement to get only customer name and address from CUSTOMERS table (ID,NAME,ADDRESS,PHONE)','mcq',ARRAY['SELECT name, address FROM customers;','SELECT * FROM customers;','SELECT id, name, address, phone FROM customers;','SELECT cust_name, cust_address FROM customers;'],0,'SELECT name, address FROM customers; returns only the needed columns.',1,21),
('b1c2d3e4-0001-4000-8000-000000000001','If the maximum cardinality is equal to 1 in both directions of a relationship, then it is','mcq',ARRAY['Optional','Many-to-many','One-to-one','One-to-many'],2,'When max cardinality is 1 in both directions it is a One-to-one relationship.',1,22),
('b1c2d3e4-0001-4000-8000-000000000001','How do you change the PRICE of BOOK whose id=B001 to value of 600?','mcq',ARRAY['CHANGE BOOK SET PRICE=600 Where ID=''B001'';','UPDATE TO CHANGE BOOK SET PRICE=600 Where ID=''B001'';','UPDATE BOOK SET PRICE=600 Where ID=''B001'';','GRANT BOOK SET PRICE=600 Where ID=''B001'';'],2,'UPDATE table SET column=value WHERE condition; is correct SQL syntax.',1,23),
('b1c2d3e4-0001-4000-8000-000000000001','The Entity Relationship (E-R) Model','mcq',ARRAY['Entities are represented by circle','Attributes are represented by rectangle','It represents conceptual view','It corresponds to row'],2,'The ER model represents a conceptual view of the database.',1,24),
('b1c2d3e4-0001-4000-8000-000000000001','Removal of transitivity property should be fulfilled in','mcq',ARRAY['First Normal Form','Fourth Normal Form','Third Normal Form','Second Normal Form'],2,'3NF removes transitive dependencies.',1,25),
('b1c2d3e4-0001-4000-8000-000000000001','If relation R has 5 tuples and relation S has 7 tuples, then Cartesian product of R and S will have','mcq',ARRAY['5+7 tuples','7-5 tuples','5X7 tuples','5/7 tuples'],2,'Cartesian product = 5 × 7 = 35 tuples.',1,26),
('b1c2d3e4-0001-4000-8000-000000000001','How do you prevent DELETE and UPDATE privileges on PRICE and YEAR of CATALOGUE table from Mohammed?','mcq',ARRAY['GRANT DELETE, UPDATE (price,year) ON catalogue From Mohammed','ALLOW DELETE, UPDATE (price,year) ON catalogue From Mohammed','REVOKE DELETE, UPDATE (price,year) ON catalogue From Mohammed','DENY DELETE, UPDATE (price,year) ON catalogue From Mohammed'],2,'REVOKE removes previously granted privileges.',1,27);
insert into public.questions (exam_id, question_text, question_type, options, correct_answer, explanation, marks, order_num) values
('b1c2d3e4-0001-4000-8000-000000000001','In C++, a variable which stores a reference to another variable is called a____','mcq',ARRAY['Pointer','Constructor','Asterisks','Structure'],0,'A pointer stores the memory address of another variable.',1,28),
('b1c2d3e4-0001-4000-8000-000000000001','A program that translates a high-level language like C++ to machine language is called a _____','mcq',ARRAY['Disassembler','Coder','Compiler','Assembler'],2,'A compiler translates high-level language to machine code.',1,29),
('b1c2d3e4-0001-4000-8000-000000000001','A=0, B=10. Which alternative is false?','mcq',ARRAY['(B==10)||(x<y)','(A>20)||(B>5)','(A>10)&&(x<y)','(A==0)&&(B<20)'],2,'(A>10) is false AND false makes the whole expression false — so C is false.',1,30),
('b1c2d3e4-0001-4000-8000-000000000001','Which one of the following format is correct for functions in structural Programming?','mcq',ARRAY['Type name { parameter1, parameter2, ...} (statement)','Name type ( parameter1, parameter2, ...) { statement }','Type name ( parameter1, parameter2, ...) {statement}','Name type { parameter1, parameter2, ...} (statement)'],2,'Correct format: return_type name(params) { body }',1,31),
('b1c2d3e4-0001-4000-8000-000000000001','Which of the following is a valid function call (assuming function add exists with two parameters)?','mcq',ARRAY['add;','add(a,b);','add a,b;','add(int a, int b);'],1,'add(a,b); is a valid function call passing two arguments.',1,32),
('b1c2d3e4-0001-4000-8000-000000000001','A function is said to be recursive function if?','mcq',ARRAY['It calls another function2 & Function3','The main function calls many functions','The main function calls another one function','The function calls itself'],3,'A recursive function is one that calls itself.',1,33),
('b1c2d3e4-0001-4000-8000-000000000001','Which of the following is not an OOPS concept?','mcq',ARRAY['Encapsulation','Polymorphism','Exception','Abstraction'],2,'Exception handling is not a core OOP concept.',1,34),
('b1c2d3e4-0001-4000-8000-000000000001','Which feature of OOPS derives the class from another class?','mcq',ARRAY['Inheritance','Data hiding','Encapsulation','Polymorphism'],0,'Inheritance allows a class to derive from another class.',1,35),
('b1c2d3e4-0001-4000-8000-000000000001','Which two features of object-oriented programming are the same?','mcq',ARRAY['Abstraction and Polymorphism','Inheritance and Encapsulation','Encapsulation and Polymorphism','Encapsulation and Abstraction'],3,'Encapsulation and Abstraction are closely related — both involve hiding details.',1,36),
('b1c2d3e4-0001-4000-8000-000000000001','Which of the following statement of a program is not right?','mcq',ARRAY['class teacher{ }; teacher s[5];','class teacher{ }s;','class teacher{ }s[];','class teacher{ }; teacher s;'],2,'class teacher{ }s[]; is invalid syntax for declaring an array of objects.',1,37);
insert into public.questions (exam_id, question_text, question_type, options, correct_answer, explanation, marks, order_num) values
('b1c2d3e4-0001-4000-8000-000000000001','Using encapsulation, security of the data is ___________','mcq',ARRAY['Ensured to some extent','Purely ensured','Not ensured','Very low'],0,'Encapsulation ensures data security to some extent by restricting direct access.',1,38),
('b1c2d3e4-0001-4000-8000-000000000001','The program with marksofstudent class returning address of private member:','mcq',ARRAY['May result in undesirable conditions','Violates the feature of encapsulation','Will generate an error','The above program is good to go'],1,'Returning address of a private member violates encapsulation.',1,39),
('b1c2d3e4-0001-4000-8000-000000000001','Which one of the following statements are true about Structure?','mcq',ARRAY['Structure is collection of homogenous members','Individual values of the Structure are called members','It is possible to initialize the Structure upon its defining','All are correct'],1,'Individual values (fields) of a structure are called members.',1,40),
('b1c2d3e4-0001-4000-8000-000000000001','An ___ is defined as a set of well-defined instructions used to accomplish a particular task.','mcq',ARRAY['Algorithm','Function','Program','Procedure'],0,'An algorithm is a finite set of well-defined instructions to solve a problem.',1,41),
('b1c2d3e4-0001-4000-8000-000000000001','The measure of the longest amount of time possibly taken to complete an algorithm is expressed as __.','mcq',ARRAY['Little-O','Little-Omega','Big-Omega','Big-O'],3,'Big-O notation describes the worst-case (maximum) time complexity.',1,42),
('b1c2d3e4-0001-4000-8000-000000000001','A ___ is a compact, informal, environment-independent description of a computer programming algorithm.','mcq',ARRAY['Stack','Queue','Pseudocode','Non-linear data structure'],2,'Pseudocode is an informal description of an algorithm.',1,43),
('b1c2d3e4-0001-4000-8000-000000000001','___ of an algorithm is the amount of time required for it to execute.','mcq',ARRAY['Time complexity','Space complexity','Compiling time','Best case'],0,'Time complexity measures the time an algorithm takes to execute.',1,44),
('b1c2d3e4-0001-4000-8000-000000000001','Potential function method performs amortized analysis based on ___.','mcq',ARRAY['Financial model','Computational model','Algorithm analysis','Energy model'],0,'The potential function method uses a financial analogy (credits/debits).',1,45),
('b1c2d3e4-0001-4000-8000-000000000001','___ is the maximum amount of time an algorithm takes to execute a specific set of inputs.','mcq',ARRAY['Running time','Average case time complexity','Worst case time complexity','Best case time complexity'],2,'Worst case time complexity is the maximum time for any input.',1,46),
('b1c2d3e4-0001-4000-8000-000000000001','Which of the following is non-linear data structure?','mcq',ARRAY['Trees','Stacks','Strings','All of the above'],0,'Trees are non-linear; stacks and strings are linear.',1,47);
insert into public.questions (exam_id, question_text, question_type, options, correct_answer, explanation, marks, order_num) values
('b1c2d3e4-0001-4000-8000-000000000001','The number of comparisons done by sequential search is .......','mcq',ARRAY['(N/2)+1','(N+1)/2','(N-1)/2','(N-2)/2'],1,'Average comparisons in sequential search = (N+1)/2.',1,48),
('b1c2d3e4-0001-4000-8000-000000000001','...... is not the operation that can be performed on queue.','mcq',ARRAY['Traversal','Insertion','Deletion','Retrieval'],0,'Traversal is not a standard queue operation; queues support enqueue, dequeue, peek.',1,49),
('b1c2d3e4-0001-4000-8000-000000000001','Which is/are the application(s) of stack?','mcq',ARRAY['Function calls','Large number Arithmetic','Evaluation of arithmetic expressions','All of the above'],3,'Stacks are used in function calls, arithmetic, and expression evaluation.',1,50),
('b1c2d3e4-0001-4000-8000-000000000001','Which of the following data structures are indexed structures?','mcq',ARRAY['Stack','Linked lists','Linear arrays','None of the above'],2,'Arrays are indexed — elements accessed by index number.',1,51),
('b1c2d3e4-0001-4000-8000-000000000001','Which of the following data structure stores homogeneous data elements?','mcq',ARRAY['Lists','Pointers','Records','Arrays'],3,'Arrays store elements of the same data type (homogeneous).',1,52);
insert into public.questions (exam_id, question_text, question_type, options, correct_answer, explanation, marks, order_num) values
('b1c2d3e4-0001-4000-8000-000000000001','Which one of the following is not a component of data communication?','mcq',ARRAY['Message','Medium','Sender','Protocol'],3,'The five components are: message, sender, receiver, medium, protocol. Protocol is a component but all are listed — wait: Protocol IS a component. Actually "Protocol" is a component. The correct odd one out trick: all are components. Re-read: sender, medium, message are components. Protocol is also a component. This tests if students know all 5.',1,53),
('b1c2d3e4-0001-4000-8000-000000000001','Which topology defines how hosts access the media to send data?','mcq',ARRAY['Logical Topology','Bus Topology','Physical Topology','Star Topology'],0,'Logical topology defines how devices access the medium to send data.',1,54),
('b1c2d3e4-0001-4000-8000-000000000001','Segmentation of a data stream happens at which layer of the OSI model?','mcq',ARRAY['Physical','Data Link','Network','Transport'],3,'Transport layer (Layer 4) segments data streams.',1,55),
('b1c2d3e4-0001-4000-8000-000000000001','When data is encapsulated, which is the correct order?','mcq',ARRAY['Data, frame, packet, segment, bit','Data, segment, packet, frame, bit','Segment, data, packet, frame, bit','Data, segment, frame, packet, bit'],1,'Correct order: Data → Segment → Packet → Frame → Bit.',1,56),
('b1c2d3e4-0001-4000-8000-000000000001','You want a network medium not susceptible to EMI. Which cabling?','mcq',ARRAY['Coaxial','Category 6 UTP','Microwave','Fiber-optic'],3,'Fiber-optic uses light, not electrical signals, so it is immune to EMI.',1,57),
('b1c2d3e4-0001-4000-8000-000000000001','Which one is not the responsibility (service) of data link layer?','mcq',ARRAY['Hardware Addressing','Media access control','Network Addressing','Logical link control'],2,'Network Addressing is handled by the Network layer, not Data Link.',1,58),
('b1c2d3e4-0001-4000-8000-000000000001','Which class of IP address provides a maximum of only 254 host addresses per network ID?','mcq',ARRAY['Class A','Class D','Class B','Class C'],3,'Class C networks support 254 host addresses (256-2).',1,59),
('b1c2d3e4-0001-4000-8000-000000000001','Which one of the following is not a component of an analogue signal?','mcq',ARRAY['Amplitude','Wavelength','Phase','Discrete pulse'],3,'Discrete pulse is a property of digital signals, not analogue signals.',1,60),
('b1c2d3e4-0001-4000-8000-000000000001','Communication between a radio station and its listeners involves ______________ transmission.','mcq',ARRAY['Full-duplex','Half-duplex','Simplex','Automatic'],2,'Radio broadcast is simplex — one direction only.',1,61),
('b1c2d3e4-0001-4000-8000-000000000001','Which of the following does not describe router functions?','mcq',ARRAY['Broadcast forwarding','Internetwork communication','Packet filtering','Packet switching'],0,'Routers do not forward broadcasts (they block them by default).',1,62);
insert into public.questions (exam_id, question_text, question_type, options, correct_answer, explanation, marks, order_num) values
('b1c2d3e4-0001-4000-8000-000000000001','Acknowledgments, sequencing, and flow control are characteristics of which OSI layer?','mcq',ARRAY['Layer 2','Layer 4','Layer 3','Layer 7'],1,'Layer 4 (Transport) handles acknowledgments, sequencing, and flow control.',1,63),
('b1c2d3e4-0001-4000-8000-000000000001','The technique of allowing multiple signals to be transmitted at the same time over the same cable is called','mcq',ARRAY['Broadcast','Multicast','Multiplexing','Demultiplexing'],2,'Multiplexing allows multiple signals to share a single channel.',1,64),
('b1c2d3e4-0001-4000-8000-000000000001','Passwords enable users to','mcq',ARRAY['Get into the system quickly','Make efficient use of time','Retain confidentiality of files','Simplify file structures'],2,'Passwords protect file confidentiality by controlling access.',1,65),
('b1c2d3e4-0001-4000-8000-000000000001','Which will NOT harm computer resources?','mcq',ARRAY['Firewall','Virus','Trojan horse','None of the above'],0,'A firewall protects resources; viruses and trojans harm them.',1,66),
('b1c2d3e4-0001-4000-8000-000000000001','A program designed to destroy data that can travel to infect other computers is called a _','mcq',ARRAY['Disease','Torpedo','Hurricane','Virus'],3,'A virus is a self-replicating program designed to damage systems.',1,67),
('b1c2d3e4-0001-4000-8000-000000000001','Trojan-Horse programs','mcq',ARRAY['Are legitimate programs that allow unauthorized access','Are hacker programs that do not show up on the system','Really do not usually work','Are usually immediately discovered'],0,'Trojan horses disguise as legitimate programs to allow unauthorized access.',1,68),
('b1c2d3e4-0001-4000-8000-000000000001','Technology, no longer protected by copyright, and is available to everyone, is considered to be:','mcq',ARRAY['Proprietary','Open','Experimental','In the public domain'],3,'Technology no longer protected by copyright is in the public domain.',1,69),
('b1c2d3e4-0001-4000-8000-000000000001','All of the following are examples of real security and privacy risks EXCEPT:','mcq',ARRAY['Hackers','Spam','Viruses','Identity theft'],1,'Spam is annoying but is the least serious security/privacy risk among these.',1,70);
insert into public.questions (exam_id, question_text, question_type, options, correct_answer, explanation, marks, order_num) values
('b1c2d3e4-0001-4000-8000-000000000001','Which of the following is not a type of Artificial Intelligence agent?','mcq',ARRAY['Learning AI agent','Goal-based AI agent','Simple reflex AI agent','Unity-based AI agent'],3,'Unity-based AI agent is not a recognized AI agent type.',1,71),
('b1c2d3e4-0001-4000-8000-000000000001','Which of the following is not the commonly used programming language for Artificial Intelligence?','mcq',ARRAY['Perl','Java','PROLOG','LISP'],0,'Perl is not commonly associated with AI. LISP, PROLOG, and Python/Java are common.',1,72),
('b1c2d3e4-0001-4000-8000-000000000001','What is the name of the AI system developed by Daniel Bobrow?','mcq',ARRAY['Program known as BACON','System known as STUDENT','Program known as SHRDLU','System known as SIMD'],1,'Daniel Bobrow developed STUDENT, an early NLP program.',1,73),
('b1c2d3e4-0001-4000-8000-000000000001','A process that is repeated, evaluated, and refined is called __________','mcq',ARRAY['Diagnostic','Descriptive','Interpretive','Iterative'],3,'An iterative process is one that repeats cycles of evaluation and refinement.',1,74),
('b1c2d3e4-0001-4000-8000-000000000001','An AI agent perceives and acts upon the environment using___.','mcq',ARRAY['Perceiver','Sensors','Actuators','Both B and C'],3,'AI agents use sensors to perceive and actuators to act on the environment.',1,75),
('b1c2d3e4-0001-4000-8000-000000000001','Which rule is applied for the Simple reflex agent?','mcq',ARRAY['Simple-action rule','Simple & Condition-action rule','Condition-action rule','None of the above'],2,'Simple reflex agents use condition-action rules (if condition then action).',1,76);
insert into public.questions (exam_id, question_text, question_type, options, correct_answer, explanation, marks, order_num) values
('b1c2d3e4-0001-4000-8000-000000000001','When does page fault occur?','mcq',ARRAY['The deadlock occurs.','The buffering occurs','The page is present in memory.','The page does not present in memory.'],3,'Page fault occurs when a required page is not in main memory.',1,77),
('b1c2d3e4-0001-4000-8000-000000000001','Which of the following is a condition that causes deadlock?','mcq',ARRAY['Mutual exclusion','Hold and wait','Circular wait','No preemption','All of these'],4,'All four conditions (mutual exclusion, hold and wait, circular wait, no preemption) cause deadlock.',1,78),
('b1c2d3e4-0001-4000-8000-000000000001','What is an operating system?','mcq',ARRAY['System service provider to the application programs','Collection of programs that manages hardware resources','Interface between the hardware and application programs','All of above'],3,'OS is all three: service provider, hardware manager, and interface.',1,79),
('b1c2d3e4-0001-4000-8000-000000000001','Which Scheduling algorithm allocates the CPU first to the process that requests the CPU first?','mcq',ARRAY['Priority scheduling','Shortest job scheduling','First-come, first-served scheduling','None of above'],2,'FCFS (First-Come, First-Served) allocates CPU in arrival order.',1,80),
('b1c2d3e4-0001-4000-8000-000000000001','What is the ready state of a process?','mcq',ARRAY['When process is unable to run until some task has been completed','When process is scheduled to run after some execution','When process is using the CPU','None of the mentioned'],1,'Ready state: process is waiting in queue to be assigned the CPU.',1,81),
('b1c2d3e4-0001-4000-8000-000000000001','A set of processes is deadlock if ____________','mcq',ARRAY['Each process is terminated','All processes are trying to kill each other','Each process is blocked and will remain so forever','None of the mentioned'],2,'Deadlock: every process in the set is blocked permanently.',1,82),
('b1c2d3e4-0001-4000-8000-000000000001','In Operating Systems, which of the following is/are CPU scheduling algorithms?','mcq',ARRAY['Priority','Round Robin','Shortest Job First','All of the mentioned'],3,'Priority, Round Robin, and SJF are all valid CPU scheduling algorithms.',1,83),
('b1c2d3e4-0001-4000-8000-000000000001','In which storage placement strategy is a program placed in the largest available hole?','mcq',ARRAY['Best fit','First fit','Worst fit','Buddy'],2,'Worst fit places a process in the largest available memory hole.',1,84),
('b1c2d3e4-0001-4000-8000-000000000001','Which of the following is a type of computer architecture?','mcq',ARRAY['Microarchitecture','Harvard Architecture','Von-Neumann Architecture','All of the mentioned'],3,'All three are recognized types of computer architecture.',1,85),
('b1c2d3e4-0001-4000-8000-000000000001','Which one is not a combinational circuit?','mcq',ARRAY['Encoder','Decoder','Multiplexer','De-multiplexer','Register'],4,'Register is a sequential circuit (has memory/state), not combinational.',1,86),
('b1c2d3e4-0001-4000-8000-000000000001','In a _________ cache organization, cache permits data to be stored in any cache block.','mcq',ARRAY['Direct Mapped','Set Associativity','Fully Associative','All'],2,'Fully associative cache allows data in any block location.',1,87);
insert into public.questions (exam_id, question_text, question_type, options, correct_answer, explanation, marks, order_num) values
('b1c2d3e4-0001-4000-8000-000000000001','If a grammar produces more than one leftmost derivation for a sentence, it is called as: _____','mcq',ARRAY['Ambiguous grammar','Perfect grammar','Associative grammar','Precedence'],0,'Ambiguous grammar: multiple leftmost derivations for the same sentence.',1,88),
('b1c2d3e4-0001-4000-8000-000000000001','The intersection of a context-free language and a regular language is ________','mcq',ARRAY['Neither context-free nor regular.','Context-free','Regular but not context-free','Both regular and context-free.'],1,'Intersection of CFL and regular language is always context-free.',1,89),
('b1c2d3e4-0001-4000-8000-000000000001','Which one of the following is not part of Turing machine?','mcq',ARRAY['Finite control','Head','Tape','Input'],3,'Input (as a separate component) is not a part — Turing machine has: tape, head, finite control.',1,90),
('b1c2d3e4-0001-4000-8000-000000000001','The output of lexical analyzer is','mcq',ARRAY['Syntax tree','Strings of characters','A set of tokens','Set of regular expressions'],2,'Lexical analyzer outputs a stream of tokens.',1,91),
('b1c2d3e4-0001-4000-8000-000000000001','Which of the following is NOT the primary role of code generator in compiler design?','mcq',ARRAY['Instruction selection','Declaration of variables','Instruction ordering','Register allocation'],1,'Declaration of variables is done during semantic analysis, not code generation.',1,92),
('b1c2d3e4-0001-4000-8000-000000000001','Which one of the following is different from the others?','mcq',ARRAY['Quadruples','Triples','Tree','Indirect triples'],2,'Tree is a graphical representation; quadruples, triples, indirect triples are all tabular intermediate representations.',1,93),
